INSERT INTO `articles` VALUES (10, '实习修复Bug碎碎念1——修复JSON反序列化失败', '记录修复OA平台任务确认功能Bug的过程。针对JSON反序列化失败，排查发现是前端传参格式错误，修改后解决。同时修复了因后端误用@RequestParam注解导致的参数接收异常问题。', 0, 'aliyun/article/20260318-article-5.md', '实习碎碎念', 'published', 'https://smjtest.oss-cn-beijing.aliyuncs.com/article/20260318-article-0.jpg', 1, 'admin', 122, 0, '2026-01-09 11:20:18', '2026-03-18 15:02:08');
INSERT INTO `articles` VALUES (11, '关于@SpringBootApplication注解与它的三个核心注解的一些体会', '@SpringBootApplication是SpringBoot应用的核心启动注解，由@SpringBootConfiguration、@EnableAutoConfiguration和@ComponentScan组成。它通过标识主配置类、自动扫描组件以及加载自动配置类，简化了配置流程，实现了应用的高效启动。', 0, 'aliyun/article/20260318-article-16.md', '实习碎碎念', 'published', 'https://smjtest.oss-cn-beijing.aliyuncs.com/article/20260318-article-13.jpg', 1, 'admin', 26, 0, '2026-01-21 14:01:43', '2026-03-18 14:37:35');
