-- ----------------------------
-- Table structure for essays
-- ----------------------------
DROP TABLE IF EXISTS `essays`;
CREATE TABLE `essays`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '随笔标题',
  `content_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '随笔正文在阿里云对象存储中的路径（aliyun/...）',
  `author_id` bigint UNSIGNED NULL DEFAULT NULL COMMENT '作者用户ID',
  `author_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '作者用户名',
  `location` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `cover_image` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '封面图片URL',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_essays_author_name`(`author_name` ASC) USING BTREE,
  INDEX `idx_essays_created_at`(`created_at` ASC) USING BTREE,
  INDEX `idx_essays_author_id`(`author_id` ASC) USING BTREE,
  INDEX `idx_essays_updated_at`(`updated_at` ASC) USING BTREE,
  CONSTRAINT `fk_essays_author` FOREIGN KEY (`author_id`) REFERENCES `users` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '随笔表' ROW_FORMAT = Dynamic;

